7	const toKey = (x: number, y: number): string => `${x},${y}`;
8	
9	const parseKey = (key: string): [number, number] => {
10	  const [x, y] = key.split(",").map(Number);
11	  return [x, y];
12	};
13	
14	export const nextGeneration = (liveCells: Set<string>): Set<string> => {
15	  const countLiveNeighbors = (x: number, y: number): number =>
16	    NEIGHBOR_OFFSETS.filter(([dx, dy]) => liveCells.has(toKey(x + dx, y + dy))).length;
17	
18	  const candidates = new Set<string>();
19	  for (const cell of liveCells) {
20	    const [x, y] = parseKey(cell);
21	    candidates.add(cell);
22	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
23	      candidates.add(toKey(x + dx, y + dy));
24	    }
25	  }
26	
27	  const nextLiveCells = new Set<string>();
28	  for (const cell of candidates) {
29	    const [x, y] = parseKey(cell);
30	    const neighbors = countLiveNeighbors(x, y);
31	    const survives = neighbors === 3 || (neighbors === 2 && liveCells.has(cell));
32	    if (survives) {
33	      nextLiveCells.add(cell);
34	    }
35	  }
36	  return nextLiveCells;
