export const nextGeneration = (liveCells: Set<string>): Set<string> => {
  const countLiveNeighbors = (x: number, y: number): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) => liveCells.has(toKey(x + dx, y + dy))).length;

  const candidates = new Set<string>();
  for (const cell of liveCells) {
    const [x, y] = parseKey(cell);
    candidates.add(cell);
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      candidates.add(toKey(x + dx, y + dy));
    }
  }

  const nextLiveCells = new Set<string>();
  for (const cell of candidates) {
    const [x, y] = parseKey(cell);
    const neighbors = countLiveNeighbors(x, y);
    const survives = neighbors === 3 || (neighbors === 2 && liveCells.has(cell));
    if (survives) {
      nextLiveCells.add(cell);
    }
  }
  return nextLiveCells;
};

